`#include &lt;bits/stdc++.h&gt;
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin &gt;&gt; T;
    while (T--) {
        int N;
        cin &gt;&gt; N;
        vector&lt;vector&lt;int&gt;&gt; adj(N + 1);
        for (int i = 0; i &lt; N - 1; i++) {
            int u, v;
            cin &gt;&gt; u &gt;&gt; v;
            adj[u].push_back(v);
            adj[v].push_back(u);
        }

        vector&lt;bool&gt; visited(N + 1, false);
        queue&lt;pair&lt;int,int&gt;&gt; q;
        q.push({1, 1});
        visited[1] = true;
        int maxDepth = 0;

        while (!q.empty()) {
            auto [node, depth] = q.front();
            q.pop();
            maxDepth = max(maxDepth, depth);
            for (int child : adj[node]) {
                if (!visited[child]) {
                    visited[child] = true;
                    q.push({child, depth + 1});
                }
            }
        }

        cout &lt;&lt; maxDepth &lt;&lt; "\n";
    }

    return 0;
}
`**Python (BFS Approach):**

`from collections import deque

def main():
    import sys
    data = sys.stdin.read().split()
    if not data:
        return
    t = int(data[0])
    index = 1
    results = []
    for _ in range(t):
        n = int(data[index])
        index += 1
        adj = [[] for _ in range(n+1)]
        for i in range(n - 1):
            u = int(data[index])
            v = int(data[index+1])
            index += 2
            adj[u].append(v)
            adj[v].append(u)
        visited = [False] * (n + 1)
        q = deque([(1, 1)])
        visited[1] = True
        max_depth = 0
        while q:
            node, depth = q.popleft()
            max_depth = max(max_depth, depth)
            for child in adj[node]:
                if not visited[child]:
                    visited[child] = True
                    q.append((child, depth + 1))
        results.append(str(max_depth))
    sys.stdout.write("\n".join(results))

if __name__ == "__main__":
    main()
